module RefModule(
  input clk,
  input reset,
  output reg [3:0] count
);reg [3:0] temp_count;

always @(posedge clk) begin
  if (reset) begin
    temp_count <= 4'b0000;
  end
  else begin
    if (temp_count == 4'b0111) begin
      temp_count <= 4'b0000;
    end
    else begin
      temp_count <= temp_count + 1;
    end
  end
end

wire __count_tmp = temp_count;
assign count = __count_tmp;

endmodule
